from flask import Flask, request, redirect

app = Flask(__name__)


def is_safe_url(target):
    # Check if the target is a relative URL (safe for redirect)
    # Reject absolute URLs, protocol-relative URLs, or URLs with schemes
    if not target:
        return False
    # Reject if it contains a scheme (e.g., http://, https://)
    if '://' in target:
        return False
    # Reject protocol-relative URLs (e.g., //example.com)
    if target.startswith('//'):
        return False
    # Ensure it starts with '/' to be a relative path
    return target.startswith('/')


@app.route('/')
def redirect():
    '''
    Redirect the user to the next_url  specified on the GET request.
    '''
    next_url = request.args.get('next_url', '')
